                try { rb.method("set_velocity").invoke(velocity); return true; } catch(_) {}
                try { rb.method("AddForce").invoke(velocity, 2); return true; } catch(_) {}
                try { rb.method("AddForce").invoke(velocity); return true; } catch(_) {}
