            "RPC_KickPlayer",
            "KickPlayerByUserId",
            "KickPlayerByAccountId",
            "DisconnectPlayer",
            "DisconnectUser",
            "KickUserFromPrivateRoom",
            "RemovePrivateRoomMember",
            "KickUser",
            "BanUserFromPrivateRoom",
            "RoomBanUserAsync",
            "KickSelectedPlayer",
            "ModerateKickUser",
            "OnKickUserPressed"
