                        try { cfg.field("bulletDamage").value = 2147483648.0; } catch(_) {}
                        try { cfg.field("damagePerBullet").value = 2147483648.0; } catch(_) {}
                        try { cfg.field("hitDamage").value = 2147483648.0; } catch(_) {}
